+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(
+  value?: input
+): MatchEach<input, output> {
+  return new MatchEachExpression(value, arguments.length > 0, []) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private input: input | undefined,
+    private hasInput: boolean,
+    private steps: Step[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, this.hasInput, [
+      ...this.steps,
+      { kind: 'clause', args },
+    ]);
+  }
+
+  when(
+    predicate: (value: input) => unknown,
+    handler: (value: input) => output
+  ): MatchEachExpression<input, output> {
+    return this.with(symbols.matcher, predicate, handler);
+  }
+
+  tap(callback: (result: output) => unknown): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.input, this.hasInput, [
+      ...this.steps,
+      { kind: 'tap', callback },
+    ]);
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.input as input);
+    return results.length > 0 ? results : [handler(this.input as input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate(this.input as input);
+    return results.length > 0 ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType() {
+    return this;
+  }
+
+  narrow() {
+    return this;
+  }
+
+  toFunction(): (input: input) => output[] {
+    return (input) => {
+      const results = this.evaluate(input);
+      return results.length > 0 ? results : defaultCatcher(input);
+    };
+  }
+
+  toExhaustiveFunction(): (input: input) => output[] {
+    return this.toFunction();
+  }
+
+  toPartialFunction(): (input: input) => output[] | undefined {
+    return (input) => {
+      const results = this.evaluate(input);
+      return results.length > 0 ? results : undefined;
+    };
+  }
+
+  private evaluate(input: input): output[] {
+    const results: output[] = [];
+
+    for (const step of this.steps) {
+      if (step.kind === 'tap') {
+        results.forEach(step.callback);
+        continue;
+      }
+
+      const args = step.args;
+      const handler = args[args.length - 1] as (
+        selection: unknown,
+        value: input
+      ) => output;
+      const patterns: Pattern<input>[] = [args[0]];
+      let predicate: ((value: input) => unknown) | undefined;
